const QDATA={"coberturas": [["Todo Riesgo - Principal", "Incendio, Rayo, Explosión, Daños por Humo, Impacto de Vehículos, Caída de Aeronaves, entre otros.  Hasta el 100% de la SA"], ["Cobertura automatica para nuevas adquisiciones (solo para contenido-bienes )", "Hasta el 15% del Valor de Contenido"], ["Otros Riesgos de la naturaleza", "Hasta el 100% de la SA"], ["Terremoto y Maremoto:", "Hasta el 100% de la SA"], ["Daños por agua", "Hasta el 100% de la SA"], ["Riesgos Políticos y Sociales:", "Huelga, Conmoción Civil, Daño Malicioso, Vandalismo y/o Terrorismo. Hasta el 100% de la SA"], ["Responsabilidad Civil", "Hasta el 100% de la SA. Max $300K"], ["Resp. Civil frente a Trabajadores del Hogar", "Resp. Civil frente a Trabajadores del Hogar.  Hasta 15% de la Suma Asegurada en Resp. Civil Familiar (Límite Agregado Vigencia)"], ["Resp. Civil frente al Propietario del Inmueble", "Resp. Civil frente al Propietario del Inmueble Alquilado.  Hasta 15% de la Suma Asegurada en Resp. Civil Familiar (Límite Agregado Vigencia)"], ["Accidentes Personales:", "-Compensación por muerte del asegurado y/o cónyuge a causa de accidente dentro de la vivienda: Hasta $ 20,000 cada uno -Gastos de sepelio del asegurado y/o cónyuge y/o hijos: Hasta $ 3,000 cada uno -Gastos médicos por accidentes a trabajadores del Hogar: Hasta $3,000 -Gastos de sepelio por muerte del trabajador del hogar: Hasta $1,000"], ["Daños al contenido Transporte por Mudanza", "Daños al contenido por  transporte del Contenido por Mudanza (*).  Hasta 100% de la suma asegurada del contenido, máximo US$ 15,000"], ["Daños Internos", "Daños Interno a Artefactos eléctricos o electrónicos. Por Evento(*): Hasta el 15% del Contenido, máximo US$ 6,000"], ["Gastos Extraordinarios", "Remoción de Escombros, Honorarios de Arquitectos, Topógrafos e Ingenieros, Documentos y Modelos.  Hasta 20% de Edificación y/o Contenido"], ["Rotura Accidental de Cristales", "Hasta el 15% de la Suma de Edificio y/o Contenido, máximo US$ 10,000"], ["Gastos de Alquiler o Alojamiento", "Alquiler de vivienda y/o alojamiento provisional en un Hotel.  Hasta US$ 1,500 por mes. Máximo 12 meses"], ["Gastos de Aceleración", "Gastos de Aceleración del remedio o reparación de daños materiales por: Horas Extras, Trabajos en horario nocturno, y en días domingos y feriados.  Hasta el 5% de la Suma de Edificio y/o Contenido"], ["Robo:", "Contenido: 100% del valor declarado Instalaciones fijas al 25% del edificio. Maximo $15,000"]], "robo": [["Robo y/o asalto de joyas (piedras preciosas -sueltas o engastadas- y metales preciosos -en forma de joyas-), relojes de uso personal, computadoras personales, proyectores, equipos de fax, instrumentos musicales, cámaras fotográficas, filmadoras de vídeo que estén siendo portados fuera del lugar del seguro, por el Asegurado y/o su cónyuge y/o sus hijos.", "15% de la suma asegurada en Contenido Hasta $2,000"], ["Robo y/o asalto de joyas (piedras preciosas -sueltas o engastadas-, metales preciosos -en forma de joyas-), perlas, platería, relojes personales, pieles, cuadros, pinturas, esculturas, frescos, murales, vitrales, dibujos y, en general, las obras de arte, muebles u objetos que tengan especial valor artístico, científico y/o histórico, que ocurran dentro del lugar del seguro.", "Limitado por cada Bien Hasta $1000, Máximo Hasta $3,500"], ["Robo y/o Asalto de dinero efectivo, dentro de la vivienda asegurada, siempre que tales bienes se encuentren en muebles cerrados con llave", "Hasta $550 por evento"], ["Robo y/o asalto de equipaje y/o bienes fuera de la vivienda portados por el asegurado y/o cónyuge y/o hijos. Viaje dentro y fuera del Perú", "15% de la suma asegurada del contenido, máximo $1,500"], ["Deshonestidad o apropiación ilícita cometida por los trabajadores del hogar.", "US$ 3,000 , sublímite de la cobertura de Robo"], ["Hurto y/o Desaparición Misteriosa de bienes asegurados dentro de la vivienda asegurada", "US$ 1,000, sublímite de la cobertura de Robo"], ["Robo y/o Asalto de dinero en efectivo dentro de la vivienda", "Hasta $550 por evento"], ["Robo y/o Asalto de dinero efectivo fuera de la vivienda asegurada portado por el asegurado y/o cónyuge", "Hasta $300 por evento"]], "asist": [["Cerrajería", "$350 por evento", "3 eventos"], ["Gasfitería", "$350 por evento", "3 eventos"], ["Electricista", "$350 por evento", "3 eventos"], ["Especialista en portones eléctricos", "$300 por evento", "1 evento"], ["Guardián en caso de robo en la vivienda", "$500 por evento", "1 evento (máx 24 hrs)"], ["Mensajero envío y recojo de paquetes (peso menor de 5 kilos)", "Ilimitado", "2 eventos"], ["Valet parking", "1 valet", "2 eventos"], ["Mozo a domicilio", "1 mozo", "2 eventos"]]};
const QLOGO="data:image/png;base64,";

(function(){
  const $ = id => document.getElementById(id);
  const EXEC_EMAIL='gonzalo_velarde1@ajg.com';
  const TI=2.2, TR=4.0, MIN=150, RECARGO=0.03, IGV=0.18, M2=500, CUOTAS=12;
  const fmt = n => 'US$ '+Number(n).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});
  let last=null;

  function syncTipo(){
    const t=$('q-tipo').value;
    const lbl=$('q-inm-label'), tog=$('q-calc-toggle');
    if(t==='casa'){ lbl.textContent='Valor de reconstrucción (US$)'; tog.hidden=false; }
    else if(t==='depto'){ lbl.textContent='Valor comercial del inmueble (US$)'; tog.hidden=true; $('q-calc').hidden=true; }
    else { lbl.textContent='Valor del inmueble (US$)'; tog.hidden=true; $('q-calc').hidden=true; }
  }
  function calcM2(){ const m=parseFloat($('q-m2').value)||0; $('q-m2-val').textContent=fmt(m*M2); }

  function cotizar(){
    const err=$('q-err'); err.hidden=true;
    const inm=parseFloat($('q-inmueble').value)||0;
    const cont=parseFloat($('q-contenido').value)||0;
    if(!$('q-tipo').value){ err.textContent='Selecciona el tipo de vivienda.'; err.hidden=false; return; }
    if(inm<=0 && cont<=0){ err.textContent='Ingresa al menos un valor asegurado (inmueble o contenido).'; err.hidden=false; return; }
    const neta=Math.max(inm*TI/1000 + cont*TR/1000, MIN);
    const com=neta*(1+RECARGO);
    const total=com*(1+IGV);
    const cuota=total/CUOTAS;
    $('r-neta').textContent=fmt(neta);
    $('r-com').textContent=fmt(com);
    $('r-total').textContent=fmt(total);
    $('r-cuota').textContent=fmt(cuota)+' /mes';
    $('q-empty').hidden=true; $('q-result').hidden=false;
    last={inm,cont,neta,com,total,cuota,
      tipo:$('q-tipo').value==='casa'?'Casa':'Departamento',
      valLabel:$('q-tipo').value==='casa'?'Valor de reconstrucción':'Valor comercial del inmueble',
      nombre:$('q-nombre').value||'—', dni:$('q-dni').value||'—', cel:$('q-cel').value||'—', mail:$('q-mail').value||'—'};
  }

  function genPDF(){
    const note=$('q-pdf-note');
    if(!window.jspdf||!window.jspdf.jsPDF){ note.textContent='No se pudo cargar el generador de PDF (requiere conexión a internet). Inténtalo nuevamente conectado.'; return; }
    if(!last){ return; }
    const { jsPDF }=window.jspdf;
    const doc=new jsPDF({unit:'pt',format:'a4'});
    const W=doc.internal.pageSize.getWidth(), M=40; let y=42;
    try{ doc.addImage(QLOGO,'PNG',W-M-74,y-6,74,74); }catch(e){}
    doc.setFont('helvetica','bold'); doc.setFontSize(18); doc.setTextColor(12,42,51);
    doc.text('Cotización · Seguro Domiciliario',M,y+10);
    doc.setFont('helvetica','normal'); doc.setFontSize(10); doc.setTextColor(90,114,123);
    doc.text('Programa Worksite · Rímac Seguros · Bróker Gallagher',M,y+28);
    const hoy=new Date().toLocaleDateString('es-PE',{year:'numeric',month:'long',day:'numeric'});
    doc.text('Fecha de cotización: '+hoy,M,y+43);
    y+=62;

    doc.autoTable({startY:y,margin:{left:M,right:M},theme:'grid',
      styles:{font:'helvetica',fontSize:9,cellPadding:5,textColor:[40,55,60]},
      headStyles:{fillColor:[12,42,51],textColor:255,fontStyle:'bold'},
      head:[['Datos de la cotización','']],
      body:[
        ['Nombre completo', last.nombre],
        ['DNI / RUC', last.dni],
        ['Moneda', 'Dólares (US$)'],['Vigencia','Anual'],
        ['Tipo de vivienda', last.tipo],
        [last.valLabel, fmt(last.inm)],
        ['Valor declarado del contenido', fmt(last.cont)],
        ['Tasa Incendio (inmueble)', '2.2 por mil'],
        ['Tasa Robo (contenido)', '4.0 por mil'],
      ],
      columnStyles:{0:{cellWidth:200,fontStyle:'bold'},1:{cellWidth:'auto'}}});
    y=doc.lastAutoTable.finalY+14;

    doc.autoTable({startY:y,margin:{left:M,right:M},theme:'grid',
      styles:{font:'helvetica',fontSize:10,cellPadding:6},
      headStyles:{fillColor:[54,168,155],textColor:255},
      head:[['Prima a cobrar','']],
      body:[
        ['Prima Neta', fmt(last.neta)],
        ['Prima Comercial (+3%)', fmt(last.com)],
        ['Prima Total (incl. IGV 18%)', fmt(last.total)],
        ['12 cuotas sin intereses', fmt(last.cuota)+' / mes'],
      ],
      columnStyles:{0:{cellWidth:280,fontStyle:'bold'},1:{cellWidth:'auto',halign:'right',fontStyle:'bold'}},
      didParseCell:function(d){ if(d.row.index===2){ d.cell.styles.fillColor=[240,164,49]; d.cell.styles.textColor=[12,42,51]; d.cell.styles.fontSize=12; } }});
    y=doc.lastAutoTable.finalY+12;
    doc.setFont('helvetica','italic');doc.setFontSize(8);doc.setTextColor(120,140,144);
    { var _fl=doc.splitTextToSize('Financiamiento: hasta 12 cuotas iguales sin intereses. El fraccionamiento aplica únicamente con descuento por planilla o con afiliación al débito automático.',W-2*M); doc.text(_fl,M,y); y+=_fl.length*11+12; }

    function section(title, head, body, w0){
      doc.autoTable({startY:y,margin:{left:M,right:M},theme:'striped',
        styles:{font:'helvetica',fontSize:8,cellPadding:4,valign:'top',textColor:[40,55,60]},
        headStyles:{fillColor:[12,42,51],textColor:255,fontStyle:'bold'},
        alternateRowStyles:{fillColor:[240,247,246]},
        head:[head], body:body,
        columnStyles: w0});
      y=doc.lastAutoTable.finalY+16;
    }
    section('Coberturas',['Cobertura','Detalle / Límite'],QDATA.coberturas,{0:{cellWidth:170,fontStyle:'bold'},1:{cellWidth:'auto'}});
    section('Coberturas adicionales de robo',['Cobertura','Límite'],QDATA.robo,{0:{cellWidth:300},1:{cellWidth:'auto'}});
    section('Asistencias',['Asistencia','Monto máximo','Tope de vigencia'],QDATA.asist,{0:{cellWidth:240,fontStyle:'bold'},1:{cellWidth:'auto'},2:{cellWidth:110}});

    if(y>740){ doc.addPage(); y=42; }
    doc.setFont('helvetica','italic'); doc.setFontSize(8); doc.setTextColor(120,140,144);
    const dl='Deducibles: aplican según el condicionado general de la póliza de Rímac Seguros. Esta cotización es referencial y está sujeta a la aceptación y condiciones de la compañía. Vigencia anual. Prima mínima US$ 150.';
    doc.text(doc.splitTextToSize(dl, W-2*M), M, y+4);

    doc.save('Cotizacion_Domiciliario_Rimac.pdf');
    note.textContent='PDF generado. Revisa tu carpeta de descargas.';
  }

  function emision(){
    if(!last){ return; }
    const subj='Solicitud de Emisión – Seguro Domiciliario – '+last.nombre;
    const b=['Estimado(a) ejecutivo(a) de Gallagher,','',
      'Un colaborador solicita la EMISIÓN de su Seguro Domiciliario (Programa Worksite – Rímac). Datos:','',
      '— CONTACTO DEL COLABORADOR —','Nombre: '+last.nombre,'Documento: '+last.dni,'Celular: '+last.cel,'Correo: '+last.mail,'',
      '— COTIZACIÓN —','Tipo de vivienda: '+last.tipo,last.valLabel+': '+fmt(last.inm),'Valor del contenido: '+fmt(last.cont),
      'Tasas: Incendio 2.2 por mil; Robo 4.0 por mil','Prima Neta: '+fmt(last.neta),'Prima Comercial (+3%): '+fmt(last.com),
      'Prima Total (incl. IGV 18%): '+fmt(last.total),'Financiamiento: 12 cuotas sin intereses de '+fmt(last.cuota)+' (con descuento por planilla o afiliacion al debito automatico)','',
      'Por favor contactar al colaborador para continuar con la emisión. Gracias.'].join('\n');
    window.location.href='mailto:'+EXEC_EMAIL+'?subject='+encodeURIComponent(subj)+'&body='+encodeURIComponent(b);
    $('q-pdf-note').textContent='Se abrió tu correo con la solicitud lista para enviar al ejecutivo de Gallagher.';
  }
  function reset(){
    ['q-nombre','q-dni','q-cel','q-mail','q-inmueble','q-contenido','q-m2'].forEach(i=>{const e=$(i); if(e) e.value='';});
    $('q-tipo').value=''; syncTipo(); $('q-calc').hidden=true; $('q-result').hidden=true;
    $('q-empty').hidden=false; $('q-err').hidden=true; $('q-pdf-note').textContent=''; last=null;
  }

  function bind(){
    $('q-tipo').addEventListener('change',syncTipo);
    $('q-calc-toggle').addEventListener('click',()=>{ const c=$('q-calc'); c.hidden=!c.hidden; });
    $('q-m2').addEventListener('input',calcM2);
    $('q-calc-apply').addEventListener('click',()=>{ const m=parseFloat($('q-m2').value)||0; $('q-inmueble').value=(m*M2)||''; $('q-calc').hidden=true; });
    $('q-cotizar').addEventListener('click',cotizar);
    $('q-pdf').addEventListener('click',genPDF);
    $('q-send').addEventListener('click',emision);
  }
  if(document.readyState!=='loading') bind(); else document.addEventListener('DOMContentLoaded',bind);
  window.QHogar={reset};
})();
